import{_ as t,O as l,H as r,f as o,k as i,i as h}from"./chunks/framework.Pt2pSV98.js";const b=JSON.parse('{"title":"Perplexity","description":"Perplexity AI 出品的 AI 搜索引擎——实时联网搜索 + AI 总结，每条引用可验证，告别 AI 幻觉","frontmatter":{"title":"Perplexity","description":"Perplexity AI 出品的 AI 搜索引擎——实时联网搜索 + AI 总结，每条引用可验证，告别 AI 幻觉","difficulty":"beginner"},"headers":[],"relativePath":"tools/perplexity.md","filePath":"tools/perplexity.md"}'),d={name:"tools/perplexity.md"};function n(s,a,c,u,p,P){const e=l("DifficultyBadge");return r(),o("div",null,[i(e,{level:"beginner"}),a[0]||(a[0]=h('<h1 id="perplexity" tabindex="-1">Perplexity <a class="header-anchor" href="#perplexity" aria-label="Permalink to &quot;Perplexity&quot;">​</a></h1><h2 id="一句话定位" tabindex="-1">一句话定位 <a class="header-anchor" href="#一句话定位" aria-label="Permalink to &quot;一句话定位&quot;">​</a></h2><p><strong>AI 时代的搜索引擎</strong>——不是用 AI 来聊天，而是用 AI 来搜索。实时联网、标注引用、多模型切换，让你获得准确、可验证的答案。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>详情</th></tr></thead><tbody><tr><td>公司</td><td>Perplexity AI</td></tr><tr><td>价格</td><td>免费 / Pro $20/月</td></tr><tr><td>类型</td><td>AI 搜索引擎</td></tr><tr><td>核心模型</td><td>Sonar / GPT-4o / Claude / Grok-3</td></tr><tr><td>首发时间</td><td>2022 年</td></tr></tbody></table><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><h3 id="🔍-联网实时搜索-ai-总结" tabindex="-1">🔍 联网实时搜索 + AI 总结 <a class="header-anchor" href="#🔍-联网实时搜索-ai-总结" aria-label="Permalink to &quot;🔍 联网实时搜索 + AI 总结&quot;">​</a></h3><p>Perplexity 的核心体验是&quot;搜索 + AI 回答&quot;：当你问一个问题，它会先实时搜索互联网，获取最新的相关信息，再用 AI 对搜索结果进行总结和提炼，给出一个结构清晰、有据可查的回答。每个回答附有来源链接，点击即可验证。</p><h3 id="📎-引用来源标注" tabindex="-1">📎 引用来源标注 <a class="header-anchor" href="#📎-引用来源标注" aria-label="Permalink to &quot;📎 引用来源标注&quot;">​</a></h3><p>这是 Perplexity 区别于 ChatGPT 的最大特点：每个结论旁边都有引用编号，标明信息出自哪个网页。你可以随时点开原始链接核实，确保不会把 AI 的&quot;幻觉&quot;当真相。</p><h3 id="🧠-多模型切换" tabindex="-1">🧠 多模型切换 <a class="header-anchor" href="#🧠-多模型切换" aria-label="Permalink to &quot;🧠 多模型切换&quot;">​</a></h3><p>免费版使用 Perplexity 自研的 Sonar 模型，Pro 版可以自由切换 GPT-4o、Claude、Grok-3 等主流模型。不同模型适合不同的搜索场景：GPT-4o 全面均衡，Claude 擅长长文分析，Grok-3 实时性最强。</p><h3 id="🔬-pro-search-深度研究" tabindex="-1">🔬 Pro Search 深度研究 <a class="header-anchor" href="#🔬-pro-search-深度研究" aria-label="Permalink to &quot;🔬 Pro Search 深度研究&quot;">​</a></h3><p>Pro 版的 Pro Search 功能可以对复杂问题进行多轮搜索和分析。它会自动拆解问题、搜索多个角度、交叉验证信息，最终生成一份结构化的深度研究报告。适合学术调研、市场分析、竞品研究等场景。</p><h3 id="📂-收藏与整理" tabindex="-1">📂 收藏与整理 <a class="header-anchor" href="#📂-收藏与整理" aria-label="Permalink to &quot;📂 收藏与整理&quot;">​</a></h3><p>可以创建不同主题的&quot;文库&quot;（Collections），将相关搜索和回答保存起来，方便后续查阅和分享。支持协作编辑，团队可以共建知识库。</p><h2 id="优势" tabindex="-1">优势 <a class="header-anchor" href="#优势" aria-label="Permalink to &quot;优势&quot;">​</a></h2><ul><li><strong>信息实时准确</strong>：联网搜索保证信息时效性，引用标注保证可验证性</li><li><strong>告别 AI 幻觉</strong>：每条结论有出处，你不会被 AI 编造的信息误导</li><li><strong>搜索体验好</strong>：界面简洁，回答结构化，比传统搜索引擎更高效</li><li><strong>多模型可选</strong>：Pro 用户可以根据需求选择最合适的底层模型</li></ul><h2 id="不足" tabindex="-1">不足 <a class="header-anchor" href="#不足" aria-label="Permalink to &quot;不足&quot;">​</a></h2><ul><li><strong>依赖搜索引擎质量</strong>：搜索结果的好坏受限于底层搜索引擎（Google、Bing）的抓取能力</li><li><strong>专业领域深度不足</strong>：对于需要深度专业知识的问题，不如直接查阅学术论文或专业数据库</li><li>免费版的 Pro Search 次数有限（每日 5 次）</li><li>中文搜索质量不如英文，部分中文网页的检索精度有待提升</li><li>对图片、视频等多媒体内容的搜索能力较弱</li></ul><h2 id="适合谁" tabindex="-1">适合谁？ <a class="header-anchor" href="#适合谁" aria-label="Permalink to &quot;适合谁？&quot;">​</a></h2><ul><li>✅ 研究者和学生：快速调研、文献搜索、事实核查</li><li>✅ 内容创作者和记者：验证信息准确性、获取新闻背景</li><li>✅ 职场人士：市场调研、竞品分析、行业动态跟踪</li><li>✅ 日常用户：替代传统搜索引擎，获得更精准的答案</li><li>✅ 需要消除 AI 幻觉的用户：把 Perplexity 作为 ChatGPT 的&quot;事实检查器&quot;</li><li>⚠️ 学术论文级别的深度研究建议配合 Google Scholar、专业数据库使用</li></ul><h2 id="关联阅读" tabindex="-1">关联阅读 <a class="header-anchor" href="#关联阅读" aria-label="Permalink to &quot;关联阅读&quot;">​</a></h2><ul><li><a href="/ai-knowledge/tools/chatgpt.html">ChatGPT</a> —— 与 Perplexity 互补，一个擅长对话创作，一个擅长搜索验证</li><li><a href="/ai-knowledge/tools/claude.html">Claude</a> —— Pro 版可切换 Claude 模型进行深度分析</li><li><a href="/ai-knowledge/tools/model-comparison.html">大模型对比</a> —— 了解不同模型的特点和适用场景</li><li><a href="/ai-knowledge/terms/llm.html">LLM</a> —— 理解 AI 搜索引擎背后的技术原理</li></ul><hr><blockquote><p>最后更新：2026.05</p></blockquote>',26))])}const x=t(d,[["render",n]]);export{b as __pageData,x as default};
